{{ retired_patterns }}

Pattern Recommender
Not sure where to start? Tell the OS about your context. Answer 3 questions to get a tailored pattern recommendation.


        1. What is your primary constraint?
        Velocity (Need to ship faster)
        Quality (Need to reduce rework)
        Alignment (Need to agree on direction)


        2. What is your team size?
        Solo Founder
        Small Team (2-10)
        Scaling (10+)


        3. What is your AI maturity?
        None (Just starting)
        Copilots (Cursor, GitHub Copilot)
        Agents (Custom scripts, n8n)


        Recommended Pattern:

        Start Over



const userContext = {};
function selectOption(category, value) { userContext[category] = value; const currentStep = document.querySelector('.step.active'); currentStep.classList.remove('active');
const nextStep = currentStep.nextElementSibling; if (nextStep && nextStep.classList.contains('step')) { nextStep.classList.add('active'); } else { showResults(); } }
function showResults() { const resultsContainer = document.getElementById('results-container'); const output = document.getElementById('recommendation-output'); resultsContainer.style.display = 'block';
let recommendation = "";
// Simple logic engine if (userContext.constraint === 'velocity') { recommendation = `

                    Frontier Agents OS
                    You need a chassis for your agents to speed up execution without crashing.
                `;
} else if (userContext.constraint === 'alignment') { recommendation = `

                    The Alignment Lens
                    Stop building the wrong things faster. Validate before you build.
                `;
} else if (userContext.size === 'scale') { recommendation = `

                    Frontier Team v1
                    You need clearly defined roles (Architect, Operator) to manage the complexity.
                `;
} else { // Default fallback recommendation = `

                    The Architect Module
                    Start by explicitly designing your system before executing.
                `;
}
output.innerHTML = recommendation; }
function resetRecommender() { userContext.constraint = null; userContext.size = null; userContext.ai = null;
document.querySelectorAll('.step').forEach(el => el.classList.remove('active')); document.getElementById('step-1').classList.add('active'); document.getElementById('results-container').style.display = 'none'; }


.recommender-widget { background: rgba(255, 255, 255, 0.03); border: 1px solid var(--border-subtle); border-radius: 8px; padding: 2rem; margin: 2rem 0; text-align: center; } .step { display: none; animation: fadeIn 0.3s ease; } .step.active { display: block; } .option-btn { display: block; width: 100%; max-width: 300px; margin: 0.5rem auto; padding: 1rem; background: transparent; border: 1px solid var(--text-tertiary); color: var(--text-secondary); border-radius: 4px; cursor: pointer; transition: all 0.2s; } .option-btn:hover { border-color: var(--text-primary); color: var(--text-primary); background: rgba(255,255,255,0.05); } .RecCard { border: 1px solid var(--accent-primary); padding: 1.5rem; border-radius: 8px; margin-top: 1rem; } .reset-btn { margin-top: 1rem; background: none; border: none; color: var(--text-tertiary); text-decoration: underline; cursor: pointer; } @keyframes fadeIn { from { opacity: 0; transform: translateY(5px); } to { opacity: 1; transform: translateY(0); } }
